const hamburger=document.getElementById("hamburger"),sideMenu=document.getElementById("sideMenu"),closeBtn=document.getElementById("closeBtn"),menuOverlay=document.getElementById("menuOverlay");hamburger.addEventListener("click",()=>{sideMenu.classList.add("active"),menuOverlay.classList.add("active")}),closeBtn.addEventListener("click",()=>{sideMenu.classList.remove("active"),menuOverlay.classList.remove("active")}),menuOverlay.addEventListener("click",()=>{sideMenu.classList.remove("active"),menuOverlay.classList.remove("active")});const faqItems=document.querySelectorAll(".faq-item");faqItems.forEach(e=>{e.querySelector(".faq-question").addEventListener("click",()=>{faqItems.forEach(t=>{t!==e&&t.classList.remove("active")}),e.classList.toggle("active")})});